const webhookData = $('WhatsApp Webhook POST').item.json;
const body = webhookData.body || webhookData;

const value = body?.entry?.[0]?.changes?.[0]?.value || {};
const message = value?.messages?.[0] || null;
const contact = value?.contacts?.[0] || {};
const status = value?.statuses?.[0] || null;

if (status && !message) {
  return [{ json: { is_valid_message: false, event_type: 'status', reason: 'WhatsApp status event ignored' } }];
}

if (!message) {
  return [{ json: { is_valid_message: false, event_type: 'unknown', reason: 'No message object found' } }];
}

function getPhoneNumber(msg) {
  if (msg?.from) return msg.from;
  if (msg?.from_user_id && msg.from_user_id.startsWith('51')) return msg.from_user_id;
  const wamid = msg?.id;
  if (wamid && wamid.startsWith('wamid.')) {
    try {
      const part = wamid.split('.')[1];
      const buf = Buffer.from(part, 'base64');
      const len = buf[2];
      if (len > 5 && len < 20) {
        const extracted = buf.toString('utf8', 3, 3 + len);
        if (/^\d+$/.test(extracted)) return extracted;
      }
    } catch (e) {}
  }
  return null;
}

const fromPhone = getPhoneNumber(message);
const type = message.type;
let text = '';
let media_id = null;

if (type === 'text') text = message?.text?.body || '';
if (type === 'audio') media_id = message?.audio?.id || null;
if (type === 'image') {
  text = message?.image?.caption || '';
  media_id = message?.image?.id || null;
}
if (type === 'document') {
  text = message?.document?.caption || '';
  media_id = message?.document?.id || null;
}

return [{
  json: {
    is_valid_message: true,
    event_type: 'message',
    from: fromPhone,
    customer_name: contact?.profile?.name || null,
    message_id: message.id,
    message_type: type,
    text,
    media_id,
    timestamp: message.timestamp,
    session_id: fromPhone,
    business_phone_number_id: value?.metadata?.phone_number_id || null,
    display_phone_number: value?.metadata?.display_phone_number || null,
    raw_message: message
  }
}];

const input = $json;
let reply = input.output || input.reply || input.text || '';
if (!reply) reply = 'Gracias por escribirnos. ¿En qué puedo ayudarte?';
if (reply.length > 3500) reply = reply.slice(0, 3400) + '\n\nTe resumo lo principal arriba.';
reply = reply.replace(/!\[.*?\]\(.*?\)/g, '').replace(/\[(.*?)\]\((.*?)\)/g, '$1 ($2)').replace(/\*\*/g, '*').replace(/#{1,6}\s/g, '').trim();
let from = input.from || input.customer_phone || input.phone || '';
try { from = from || $('Normalize WhatsApp Message').first().json.from; } catch (e) {}
return [{ json: { from, reply } }];

